import React from "react"
import { graphql, Link } from "gatsby"

import Layout from "../components/layout"
import Pagination from "../components/pagination"
import SEO from "../components/seo"
import { useSiteMetadata } from '../hooks';
import PostListItem from "../components/molocules/post-list-item"

const PostList = ({ data, pageContext, location }) => {
  const { title: siteTitle, subtitle: siteSubtitle } = useSiteMetadata();
  const posts = data.allMarkdownRemark.edges

  const {
    currentPage,
    totalPage,
    hasNextPage,
    hasPrevPage,
    prevPagePath,
    nextPagePath,
  } = pageContext

  return (
    <Layout showProfile location={location}>
      <SEO />
      <ol style={{ listStyle: `none` }}>
        {posts.map(edge => {
          let post = edge.node
          const title = post.frontmatter.title || post.fields.slug

          return (
            <li key={post.fields.slug} style={{ marginBottom: `20px` }}>
              <PostListItem
                 title={title}
                 url={post.fields.slug}
                 description={post.frontmatter.description || post.excerpt}
                 date={post.frontmatter.date}
              />
              {/* <article
                className="post-list-item"
                itemScope
                itemType="http://schema.org/Article"
              >
                    <Link to={post.fields.slug} itemProp="url">
                <header>
                      <span itemProp="headline">{title}</span>
                      <aside className={containerStyles.dates}>{post.frontmatter.date}</aside>
                </header>
                    </Link>
                <section>
                  <p
                    dangerouslySetInnerHTML={{
                      __html: post.frontmatter.description || post.excerpt,
                    }}
                    itemProp="description"
                  />
                </section>
              </article> */}
            </li>
          )
        })}
      </ol>
      {/* {currentPage} / {totalPage} */}
      <Pagination
          prevPagePath={prevPagePath}
          nextPagePath={nextPagePath}
          hasPrevPage={hasPrevPage}
          hasNextPage={hasNextPage}
        />
    </Layout>
  )
}

export default PostList

export const query = graphql`
query PostList($postsLimit: Int!, $postsOffset: Int!) {
  allMarkdownRemark(
      limit: $postsLimit,
      skip: $postsOffset,
      filter: { frontmatter: { template: { eq: "post" }, draft: { ne: true } } },
      sort: { order: DESC, fields: [frontmatter___date] }
    ){
    edges {
      node {
        fields {
          slug
        }
        frontmatter {
          title
          date(formatString: "MMM DD, YYYY")
          description
        }
      }
    }
  }
}
`
